#include <stdio.h>
int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X; 
        scanf("%d", &X);
        int r = X % 3;
        int ans = (r == 0) ? 0 : (r == 1) ? 2 : 1;
        printf("%d\n", ans);
    }
    return 0;
}

